use rust_daily_lesson::domain::{EmailAddress, NewUser, RegisterUserCommand, UserId};

struct FakeRepo {
    exists: bool,
}

impl UserRepository for FakeRepo {
    fn exists_by_email(&self, _email: &EmailAddress) -> Result<bool, RepositoryError> {
        Ok(self.exists)
    }

